// // This module implements a synchronous D flip-flop with an enable feature. The flip-flop captures the input data (D) on the falling edge of the clock (CLK) only when the enable (DE) signal is deasserted.
module top_module(
    output Q,
    input CLK,
    input D,
    input DE
);reg Q_reg;

    always @(posedge CLK) begin
        if (DE) begin
            Q_reg <= D;
        end
    end

    assign Q = Q_reg;

endmodule
